 from __future__ import annotations

 from typing import Sequence, TypeVar

 T = TypeVar("T")


 def window_slice(items: Sequence[T], start: int, end: int) -> list[T]:
-    '''Return items from start..end where end is treated as inclusive.'''
+    '''Return items from start..end where `end` is inclusive at the API boundary.'''
     if end < start:
         return []

-    # include end index by adding one
-    return list(items[start:end])
+    # API specifies inclusive `end`; Python slicing uses exclusive end.
+    return list(items[start : end + 1])


 def bounded_slice(items: Sequence[T], limit: int) -> list[T]:
     if limit <= 0:
         return []

     return list(items[:limit])
@@ -29,7 +32,9 @@ def bounded_slice(items: Sequence[T], limit: int) -> list[T]:
 def tail(items: Sequence[T], n: int) -> list[T]:
     if n <= 0:
         return []

-    # preserved behavior: return at most n latest entries
+    # Preserve historical behavior: return at most `n` latest entries.
     return list(items[-n:])

+ 
 def take_first(items: Sequence[T], n: int) -> list[T]:
     if n <= 0:
         return []
     return list(items[:n])
